import{_ as o,o as t,c as a,a3 as n}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Setting Up AI Providers","description":"Configure AI settings, API keys, local endpoints, and feature flags.","frontmatter":{"title":"Setting Up AI Providers","description":"Configure AI settings, API keys, local endpoints, and feature flags.","keywords":"AI settings, API key, Ollama, OpenAI, Gemini, Groq, HuggingFace, ONNX, BGE embeddings","category":"AI"},"headers":[],"relativePath":"ai/setup.md","filePath":"ai/setup.md","lastUpdated":1784869909000}'),i={name:"ai/setup.md"};function s(r,e,l,d,c,g){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="ai-setup" tabindex="-1">AI Setup <a class="header-anchor" href="#ai-setup" aria-label="Permalink to &quot;AI Setup&quot;">​</a></h1><p>Configure LLM provider models, API tokens, and local vector index settings inside <strong>AI → AI Settings</strong>.</p><hr><h2 id="_1-text-generation-providers" tabindex="-1">1. Text Generation Providers <a class="header-anchor" href="#_1-text-generation-providers" aria-label="Permalink to &quot;1. Text Generation Providers&quot;">​</a></h2><p>Notely uses the <strong>Vercel AI SDK</strong> and local bindings to connect to multiple LLM APIs:</p><ul><li><strong>Local (Qwen2.5-0.5B)</strong>: Runs completely on-device and offline. Requires downloading local GGUF weights (~400MB) via the settings dashboard.</li><li><strong>Google Gemini</strong>: Requires a Gemini API key. Highly recommended for rich tool calling.</li><li><strong>Groq</strong>: Requires a Groq API key (supports models like <code>llama-3.3-70b-specdec</code>).</li><li><strong>OpenAI Compatible</strong>: Connect to OpenAI or local servers (Ollama, LM Studio) by setting a custom Base URL and Model name.</li><li><strong>Connection Diagnostics</strong>: Click the <strong>Test</strong> button next to any configured provider to run a diagnostic round-trip test.</li></ul><hr><h2 id="_2-embedding-index-setup" tabindex="-1">2. Embedding Index Setup <a class="header-anchor" href="#_2-embedding-index-setup" aria-label="Permalink to &quot;2. Embedding Index Setup&quot;">​</a></h2><p>Vector embeddings enable Semantic Search and Context Retrieval:</p><ul><li><strong>Local BGE Model (Recommended)</strong>: Runs entirely offline inside your app. Downloads a lightweight <code>BGE-small-en-v1.5</code> ONNX model (~130MB) into <code>%AppData%/notely/ai-model/</code> and runs vector calculations locally via <code>onnxruntime-node</code>.</li><li><strong>HuggingFace API</strong>: Runs cloud-based embeddings using an API key token.</li></ul><hr><h2 id="_3-knowledge-graph-engine" tabindex="-1">3. Knowledge Graph Engine <a class="header-anchor" href="#_3-knowledge-graph-engine" aria-label="Permalink to &quot;3. Knowledge Graph Engine&quot;">​</a></h2><p>Relationship extraction and entity graph generation:</p><ul><li><strong>Local Model</strong>: Uses the local <code>Qwen2.5-0.5B</code> GGUF engine to discover and record note relationships offline.</li><li><strong>Text Provider</strong>: Automatically leverages your active cloud model configured in the main text settings tab.</li></ul><hr><h2 id="_4-sqlite-database-locality" tabindex="-1">4. SQLite Database Locality <a class="header-anchor" href="#_4-sqlite-database-locality" aria-label="Permalink to &quot;4. SQLite Database Locality&quot;">​</a></h2><p>All AI databases are workspace-scoped and stored inside the hidden <code>{workspace}/.notes-app/</code> folder to keep your data local and portable:</p><ol><li><code>ai-embeddings.db</code>: Stores chunk text, line mappings, content hashes, and indexing queues.</li><li><code>ai-graph.db</code>: Stores extracted entity nodes and relationships.</li><li><code>ai-memory.db</code>: Stores conversation sessions, message logs, and pattern analysis.</li></ol><p>PRAGMA <code>journal_mode = WAL</code> and <code>synchronous = NORMAL</code> are enabled across all databases for high performance without write blocks.</p>',19)])])}const h=o(i,[["render",s]]);export{u as __pageData,h as default};
